CREATE TABLE calls (
  id TEXT PRIMARY KEY,
  ts TEXT,
  project TEXT,
  provider TEXT,
  model TEXT,
  tokens_in INTEGER,
  tokens_out INTEGER,
  cost_usd REAL,
  outcome TEXT,
  correlation_id TEXT,
  cost_basis TEXT,
  cost_kind TEXT,
  cost_accuracy TEXT,
  cost_source TEXT,
  pricing_version TEXT,
  observation_role TEXT,
  provider_request_id TEXT,
  origin TEXT,
  budget_eligible INTEGER
);

